module.render:
    const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const color = args.color || 'var(--accent-color)';
    let titleStr = sections[0] ? sections[0].trim() : '';
    const contentStr = sections[1] ? sections[1].trim() : '';
    const icon = (args.icon && String(args.icon).trim()) || '';
    if (icon) titleStr = esc(icon) + ' ' + titleStr;
    const fill = String(args.accentfill) === 'true';
    const bw = (args.border && String(args.border).trim()) || '6px';
    const radius = (args.radius && String(args.radius).trim()) || 'var(--radius-sm)';
    const cls = 'mdp-mod-infobox' + (fill ? ' mdp-ib-fill' : '');
    return `\n\n<div class="${cls}" style="border-left-color: ${color}; --ib-c: ${color}; --ib-bw: ${bw}; --ib-radius: ${radius};"><div class="infobox-header" style="color: ${color};">

${titleStr}

</div><div class="infobox-body">

${contentStr}

</div></div>\n\n`;
